// Group markets by event, find correlated pairs where exclusive outcome prices don't sum to 1.0
const markets = $input.all();
const THRESHOLD = 0.05; // 5% mispricing threshold

// Group by event (groupItemTitle or eventSlug)
const eventGroups = {};
for (const item of markets) {
  const m = item.json;
  const eventKey = m.groupItemTitle || m.eventSlug || m.conditionId;
  if (!eventKey) continue;

  if (!eventGroups[eventKey]) {
    eventGroups[eventKey] = [];
  }

  // Parse outcome prices (Gamma returns JSON-encoded strings)
  let outcomePrices = m.outcomePrices || [];
  if (typeof outcomePrices === 'string') {
    try { outcomePrices = JSON.parse(outcomePrices); } catch(e) { outcomePrices = []; }
  }

  let outcomes = m.outcomes || [];
  if (typeof outcomes === 'string') {
    try { outcomes = JSON.parse(outcomes); } catch(e) { outcomes = []; }
  }

  const yesPrice = Number(outcomePrices[0] || 0);
  const noPrice = Number(outcomePrices[1] || 0);

  eventGroups[eventKey].push({
    question: m.question || 'Unknown',
    conditionId: m.conditionId || '',
    yesPrice,
    noPrice,
    volume: Number(m.volume || 0),
    slug: m.slug || ''
  });
}

// Check multi-outcome events for mispricing
const mispricings = [];

for (const [eventName, eventMarkets] of Object.entries(eventGroups)) {
  if (eventMarkets.length < 2) continue;

  // Sum all YES prices across outcomes in this event
  const yesSum = eventMarkets.reduce((sum, m) => sum + m.yesPrice, 0);
  const deviation = Math.abs(yesSum - 1.0);

  if (deviation > THRESHOLD) {
    const marketDetails = eventMarkets
      .map(m => `  ${m.question}: YES=$${m.yesPrice.toFixed(3)}`)
      .join('\n');

    mispricings.push({
      json: {
        event: eventName,
        marketCount: eventMarkets.length,
        yesSum: yesSum.toFixed(3),
        deviation: (deviation * 100).toFixed(1),
        direction: yesSum > 1 ? 'overpriced' : 'underpriced',
        markets: eventMarkets,
        message: `Mispricing detected in "${eventName}"\n${eventMarkets.length} outcomes, YES prices sum to $${yesSum.toFixed(3)} (${(deviation * 100).toFixed(1)}% off)\n${yesSum > 1 ? 'Overpriced' : 'Underpriced'} -- potential arb opportunity\n\n${marketDetails}`
      }
    });
  }
}

if (mispricings.length === 0) {
  return [{ json: { _noMispricings: true } }];
}

return mispricings;
